import { meetsContrastGuidelines } from 'polished';
import { ThemeProvider } from 'styled-components';

const palette = {
  gray900: '#111827',
  gray50:  '#F9FAFB',
  blue600: '#2563EB',
  white:   '#FFFFFF',
};

const validate = (bg: string, fg: string) => {
  const result = meetsContrastGuidelines(fg, bg);
  if (!result.AA) throw new Error(`Contrast fail: ${fg} on ${bg}`);
};

validate(palette.gray900, palette.white); // textPrimary on surface
validate(palette.blue600, palette.white); // brand on surface

