// theme.d.ts — extend DefaultTheme for full inference
import 'styled-components';
declare module 'styled-components' {
  export interface DefaultTheme {
    colors: { action: { default: string; hover: string } };
    radii: { md: string };
  }
}

// Button.tsx
import styled, { css } from 'styled-components';

const focusRing = css`
  outline: 2px solid ${({ theme }) => theme.colors.action.default};
  outline-offset: 2px;
`;

export const Button = styled.button`
  background: ${({ theme }) => theme.colors.action.default};
  border-radius: ${({ theme }) => theme.radii.md};
  &:focus-visible { ${focusRing} }
  &:hover { background: ${({ theme }) => theme.colors.action.hover}; }
`;

import styled, { css } from 'styled-components';

// Define css blocks OUTSIDE the component — stable reference, no re-injection
const focusRing = css`
  outline: 2px solid ${({ theme }) => theme.colors.focus};
  outline-offset: 2px;
`;

const Button = styled.button<{ $variant: 'primary' | 'ghost' }>`
  ${focusRing}
  background: ${({ theme, $variant }) =>
    $variant === 'primary' ? theme.colors.primary : 'transparent'};
  padding: ${({ theme }) => theme.spacing.md};
`;

